+///     apply t1b to (lo[1]=r1', hi[1]=r3'): r1'' = r1' + r3'*t1b,  r3'' = r1' - r3'*t1b
+///
+/// By processing both layers in a single pass, each row is loaded and stored only once,
+/// halving memory bandwidth for these two layers.
+fn dit_layer_first2<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    t0: F,   // uniform twiddle for layer 0 (same for all blocks)
+    t1a: F,  // twiddle for layer 1, first row-pair per block (lo[0], hi[0])
+    t1b: F,  // twiddle for layer 1, second row-pair per block (lo[1], hi[1])
+) {
+    let width = submat.width();
+
+    // Pre-broadcast all twiddles once for the entire function.
+    let t0_packed = F::Packing::from(t0);
+    let t1a_packed = F::Packing::from(t1a);
+    let t1b_packed = F::Packing::from(t1b);
+
+    // Each mega-block is 4 rows = 4*width elements.
+    // All mega-blocks within the submat use the same twiddles (t0, t1a, t1b).
+    for quad in submat.values.chunks_mut(4 * width) {
+        // Split the 4-row block into 4 individual rows.
+        let (r0, rest) = quad.split_at_mut(width);
+        let (r1, rest) = rest.split_at_mut(width);
+        let (r2, r3) = rest.split_at_mut(width);
+
+        // Process packed chunks.
+        let (r0_packed, r0_suffix) = F::Packing::pack_slice_with_suffix_mut(r0);
+        let (r1_packed, r1_suffix) = F::Packing::pack_slice_with_suffix_mut(r1);
+        let (r2_packed, r2_suffix) = F::Packing::pack_slice_with_suffix_mut(r2);
+        let (r3_packed, r3_suffix) = F::Packing::pack_slice_with_suffix_mut(r3);
+
+        for (p0, p1, p2, p3) in izip!(
+            r0_packed.iter_mut(),
+            r1_packed.iter_mut(),
+            r2_packed.iter_mut(),
+            r3_packed.iter_mut()
+        ) {
+            // Layer 0: apply uniform t0 to row-pairs (r0,r1) and (r2,r3).
+            let r1t = *p1 * t0_packed;
+            let r3t = *p3 * t0_packed;
+            let new_r0 = *p0 + r1t; // r0' = r0 + r1*t0
+            let new_r1 = *p0 - r1t; // r1' = r0 - r1*t0
+            let new_r2 = *p2 + r3t; // r2' = r2 + r3*t0
+            let new_r3 = *p2 - r3t; // r3' = r2 - r3*t0
+
+            // Layer 1: lows=[new_r0, new_r1], highs=[new_r2, new_r3]
+            //   apply t1a to (lo[0]=new_r0, hi[0]=new_r2)
+            //   apply t1b to (lo[1]=new_r1, hi[1]=new_r3)
+            let r2t = new_r2 * t1a_packed;
+            let r3t = new_r3 * t1b_packed;
+            *p0 = new_r0 + r2t; // r0'' = r0' + r2'*t1a
+            *p2 = new_r0 - r2t; // r2'' = r0' - r2'*t1a
+            *p1 = new_r1 + r3t; // r1'' = r1' + r3'*t1b
+            *p3 = new_r1 - r3t; // r3'' = r1' - r3'*t1b
+        }
+
+        // Scalar suffix.
+        for (s0, s1, s2, s3) in izip!(
+            r0_suffix.iter_mut(),
+            r1_suffix.iter_mut(),
+            r2_suffix.iter_mut(),
+            r3_suffix.iter_mut()
+        ) {
+            // Layer 0.
+            let r1t = *s1 * t0;
+            let r3t = *s3 * t0;
+            let new_r0 = *s0 + r1t;
+            let new_r1 = *s0 - r1t;
+            let new_r2 = *s2 + r3t;
+            let new_r3 = *s2 - r3t;
+
+            // Layer 1.
+            let r2t = new_r2 * t1a;
+            let r3t = new_r3 * t1b;
+            *s0 = new_r0 + r2t;
+            *s2 = new_r0 - r2t;
+            *s1 = new_r1 + r3t;
+            *s3 = new_r1 - r3t;
+        }
+    }
+}

