+/// This holds for layer=1 in the bit-reversed twiddle layout used by `first_half_general`.
+fn dit_layer_two_uniform_twiddles<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    t0: F,
+    t1: F,
+    backwards: bool,
+) {
+    let width = submat.width();
+    // Pre-broadcast both twiddles into packed fields once.
+    let t0_packed = F::Packing::from(t0);
+    let t1_packed = F::Packing::from(t1);
+
+    // Process each 4-row block (block_size=4 for layer=1).
+    // Each block: lo=[r0,r1], hi=[r2,r3]
+    //   r0,r2 pair uses t0; r1,r3 pair uses t1.
+    let process_block = |block: &mut [F]| {
+        // block is 4*width elements: [r0|r1|r2|r3]
