+        let (r1, rest) = rest.split_at_mut(width);
+        let (r2, r3) = rest.split_at_mut(width);
+
+        // Apply t0 to (r0, r2) pair.
+        let (r0_packed, r0_suffix) = F::Packing::pack_slice_with_suffix_mut(r0);
+        let (r2_packed, r2_suffix) = F::Packing::pack_slice_with_suffix_mut(r2);
+        for (lp, hp) in r0_packed.iter_mut().zip(r2_packed.iter_mut()) {
+            let x2t = *hp * t0_packed;
+            let new_lo = *lp + x2t;
+            *hp = *lp - x2t;
+            *lp = new_lo;
+        }
+        for (ls, hs) in r0_suffix.iter_mut().zip(r2_suffix.iter_mut()) {
+            let x2t = *hs * t0;
+            let new_lo = *ls + x2t;
+            *hs = *ls - x2t;
+            *ls = new_lo;
+        }
+
+        // Apply t1 to (r1, r3) pair.
+        let (r1_packed, r1_suffix) = F::Packing::pack_slice_with_suffix_mut(r1);
+        let (r3_packed, r3_suffix) = F::Packing::pack_slice_with_suffix_mut(r3);
+        for (lp, hp) in r1_packed.iter_mut().zip(r3_packed.iter_mut()) {
+            let x2t = *hp * t1_packed;
+            let new_lo = *lp + x2t;
+            *hp = *lp - x2t;
+            *lp = new_lo;
+        }
+        for (ls, hs) in r1_suffix.iter_mut().zip(r3_suffix.iter_mut()) {
+            let x2t = *hs * t1;
+            let new_lo = *ls + x2t;
+            *hs = *ls - x2t;
+            *ls = new_lo;
+        }
