+        let (r4_p, r4_s) = F::Packing::pack_slice_with_suffix_mut(r4);
+        let (r5_p, r5_s) = F::Packing::pack_slice_with_suffix_mut(r5);
+        let (r6_p, r6_s) = F::Packing::pack_slice_with_suffix_mut(r6);
