+            // Layer rev==2.
+            let r4t = *s4 * t2;
+            let r5t = *s5 * t2;
+            let r6t = *s6 * t2;
+            let r7t = *s7 * t2;
+            let a0 = *s0 + r4t;
+            let a1 = *s1 + r5t;
+            let a2 = *s2 + r6t;
+            let a3 = *s3 + r7t;
+            let a4 = *s0 - r4t;
+            let a5 = *s1 - r5t;
+            let a6 = *s2 - r6t;
+            let a7 = *s3 - r7t;
