+            // Layer rev==1.
+            let a2t = a2 * t1a;
+            let a3t = a3 * t1a;
+            let a6t = a6 * t1b;
+            let a7t = a7 * t1b;
+            let b0 = a0 + a2t;
+            let b1 = a1 + a3t;
+            let b2 = a0 - a2t;
+            let b3 = a1 - a3t;
+            let b4 = a4 + a6t;
+            let b5 = a5 + a7t;
+            let b6 = a4 - a6t;
+            let b7 = a5 - a7t;
+
+            // Layer rev==0.
+            let b1t = b1 * t0a;
+            let b3t = b3 * t0b;
+            let b5t = b5 * t0c;
+            let b7t = b7 * t0d;
+            *s0 = b0 + b1t;
+            *s1 = b0 - b1t;
+            *s2 = b2 + b3t;
+            *s3 = b2 - b3t;
+            *s4 = b4 + b5t;
+            *s5 = b4 - b5t;
+            *s6 = b6 + b7t;
+            *s7 = b6 - b7t;
+        }
+    }
+}

