+        let (r2, rest) = rest.split_at_mut(width);
+        let (r3, rest) = rest.split_at_mut(width);
+        let (r4, rest) = rest.split_at_mut(width);
+        let (r5, rest) = rest.split_at_mut(width);
+        let (r6, rest) = rest.split_at_mut(width);
+        let (r7, rest) = rest.split_at_mut(width);
+        let (r8, rest) = rest.split_at_mut(width);
+        let (r9, rest) = rest.split_at_mut(width);
+        let (r10, rest) = rest.split_at_mut(width);
+        let (r11, rest) = rest.split_at_mut(width);
+        let (r12, rest) = rest.split_at_mut(width);
