+            let r11t = *u11 * t3;
+            let r12t = *u12 * t3;
+            let r13t = *u13 * t3;
+            let r14t = *u14 * t3;
+            let r15t = *u15 * t3;
+            let n0  = *u0  + r8t;  let n8  = *u0  - r8t;
+            let n1  = *u1  + r9t;  let n9  = *u1  - r9t;
+            let n2  = *u2  + r10t; let n10 = *u2  - r10t;
+            let n3  = *u3  + r11t; let n11 = *u3  - r11t;
+            let n4  = *u4  + r12t; let n12 = *u4  - r12t;
+            let n5  = *u5  + r13t; let n13 = *u5  - r13t;
+            let n6  = *u6  + r14t; let n14 = *u6  - r14t;
