+            let n5t  = n5  * t2a;
+            let n6t  = n6  * t2a;
+            let n7t  = n7  * t2a;
+            let n12t = n12 * t2b;
+            let n13t = n13 * t2b;
+            let n14t = n14 * t2b;
+            let n15t = n15 * t2b;
