+            *u0  = n0  + n4t;
+            *u1  = n1  + n5t;
+            *u2  = n2  + n6t;
+            *u3  = n3  + n7t;
+            *u4  = n0  - n4t;
+            *u5  = n1  - n5t;
+            *u6  = n2  - n6t;
+            *u7  = n3  - n7t;
+            *u8  = n8  + n12t;
+            *u9  = n9  + n13t;
