+/// then reuses them across all blocks. This eliminates:
+/// - Per-block iterator clone overhead
+/// - Per-block twiddle broadcasts (reduced from `half_block_size × num_blocks` to
+///   just `half_block_size` total broadcasts)
+///
+/// Correctness: Only valid when all blocks use the same twiddle sequence from index 0,
+/// i.e., in `first_half_general` where each block's twiddle iterator is cloned from start.
+/// Only beneficial (and should only be called) when there are >= 2 blocks per submat.
+fn dit_layer_prebroadcast<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    layer: usize,
+    twiddles: &[F],
+    backwards: bool,
+) {
+    let half_block_size = 1 << layer;
+    let block_size = half_block_size * 2;
+    let width = submat.width();
+    debug_assert!(submat.height() >= block_size);
+    debug_assert!(twiddles.len() >= half_block_size);
+
+    // Pre-broadcast all half_block_size twiddles into packed fields once.
+    // This amortizes the broadcast cost over all blocks in the submat.
+    let twiddles_packed: Vec<F::Packing> = twiddles[..half_block_size]
+        .iter()
+        .map(|&t| F::Packing::from(t))
+        .collect();
+
+    let process_block = |block: &mut [F]| {
+        let (lows, highs) = block.split_at_mut(half_block_size * width);
+        for (row_idx, (lo, hi)) in lows
+            .chunks_mut(width)
+            .zip(highs.chunks_mut(width))
+            .enumerate()
+        {
+            let twiddle = twiddles[row_idx];
+            let twiddle_packed = twiddles_packed[row_idx];
+            let (lo_packed, lo_suffix) = F::Packing::pack_slice_with_suffix_mut(lo);
+            let (hi_packed, hi_suffix) = F::Packing::pack_slice_with_suffix_mut(hi);
+            for (lp, hp) in lo_packed.iter_mut().zip(hi_packed.iter_mut()) {
+                let x2t = *hp * twiddle_packed;
+                let new_lo = *lp + x2t;
+                *hp = *lp - x2t;
+                *lp = new_lo;
+            }
+            for (ls, hs) in lo_suffix.iter_mut().zip(hi_suffix.iter_mut()) {
+                let x2t = *hs * twiddle;
+                let new_lo = *ls + x2t;
+                *hs = *ls - x2t;
+                *ls = new_lo;
+            }
+        }
+    };
+
+    let blocks = submat.values.chunks_mut(block_size * width);
+    if backwards {
+        for block in blocks.rev() {
+            process_block(block);
+        }
+    } else {
+        for block in blocks {
+            process_block(block);
+        }
+    }
+}
